mapper.insert:
/** UsptExtrcMfcmmDao.insertList */
insert into uspt_extrc_mfcmm (
	   extrc_mfcmm_id
	 , mfcmm_extrc_id
	 , expert_id
	 , lsn_result_cd
	 , creator_id
	 , created_dt
) values

	(
	   #{item.extrcMfcmmId}
	 , #{item.mfcmmExtrcId}
	 , #{item.expertId}
	 , #{item.lsnResultCd}
	 , #{item.creatorId}
	 , #{item.createdDt}
	)

mapper.update:
/** UsptExtrcMfcmmDao.update */
update uspt_extrc_mfcmm set
	   lsn_result_cd         	= #{lsnResultCd}
	 , updater_id                = #{updaterId}
	 , updated_dt                = #{updatedDt}
where extrc_mfcmm_id = #{extrcMfcmmId}

mapper.delete:
/** UsptExtrcMfcmmDao.deleteByCmitId */
delete
  from uspt_extrc_mfcmm
 where mfcmm_extrc_id in (
 						  select mfcmm_extrc_id
 						    from uspt_evl_mfcmm_extrc
						   where evl_cmit_id = #{evlCmitId}
						 )
